INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000601, 'single', '90006', '對於核計勞工所得有無低於基本工資，下列敘述何者有誤？', '僅計入在正常工時內之報酬,應計入加班費,不計入休假日出勤加給之工資,不計入競賽獎金 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000602, 'single', '90006', '下列何者之工資日數得列入計算平均工資？', '請事假期間,職災醫療期 間,發生計算事由之前6 個月,放無薪假期間 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000603, 'single', '90006', '以下對於「例假」之敘述，何者有誤？', '每7 日應休息1 日,工資照給,出勤時，工資加倍及補休,須給假，不必給工資 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000604, 'single', '90006', '勞動基準法第84 條之1 規定之工作者，因工作性質特殊，就其工作時 間，下列何者正確？', '完全不受限制,無例假與休假,不另給予延時工 資,勞雇間應有合理協商彈性 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000605, 'single', '90006', '依勞動基準法規定，雇主應置備勞工工資清冊並應保存幾年？', '1 年,2 年,5 年,10 年 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000606, 'single', '90006', '事業單位僱用勞工多少人以上者，應依勞動基準法規定訂立工作規則？', '200 人,100 人,50 人,30 人 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000607, 'single', '90006', '依勞動基準法規定，雇主延長勞工之工作時間連同正常工作時間，每日不得超過多少小時？', '10,11,12,15 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000608, 'single', '90006', '依勞動基準法規定，下列何者屬不定期契約？', '臨時性或短期性的工作,季節性的工作,特定性的工作,有繼續性的工作 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000609, 'single', '90006', '依職業安全衛生法規定，事業單位勞動場所發生死亡職業災害時，雇主應 於多少小時內通報勞動檢查機構？', '8,12,24,48 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000610, 'single', '90006', '事業單位之勞工代表如何產生？', '由企業工會推派之,由產業工會推派 之,由勞資雙方協議推派之,由勞工輪流擔任之 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000611, 'single', '90006', '職業安全衛生法所稱有母性健康危害之虞之工作，不包括下列何種工作型態？', '長時間站立姿勢作業,人力提舉、搬運及推拉重物,輪班及夜間 工作,駕駛運輸車輛 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000612, 'single', '90006', '依職業安全衛生法施行細則規定，下列何者非屬特別危害健康之作業？', '噪音作業,游離輻射作業,會計作業,粉塵作業 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000613, 'single', '90006', '從事於易踏穿材料構築之屋頂修繕作業時，應有何種作業主管在場執行主 管業務？', '施工架組配,擋土支撐組配,屋頂,模板支撐 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000614, 'single', '90006', '以下對於「工讀生」之敘述，何者正確？', '工資不得低於基本工資之80 ％,屬短期工作者，加班只能補休,每日正常工作時間得超過8 小時,國定假日出勤，工資加倍發給 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000615, 'single', '90006', '勞工工作時手部嚴重受傷，住院醫療期間公司應按下列何者給予職業災害 補償？', '前6 個月平均工資,前1 年平均工資,原領工資,基本工 資 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000616, 'single', '90006', '勞工在何種情況下，雇主得不經預告終止勞動契約？', '確定被法院判刑6 個月以內並諭知緩刑超過1 年以上者,不服指揮對雇主暴力相向者,經 常遲到早退者,非連續曠工但1 個月內累計達3 日以上者 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000617, 'single', '90006', '對於吹哨者保護規定，下列敘述何者有誤？', '事業單位不得對勞工申訴人 終止勞動契約,勞動檢查機構受理勞工申訴必須保密,為實施勞動檢 查，必要時得告知事業單位有關勞工申訴人身分,任何情況下，事業單位 都不得有不利勞工申訴人之行為 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000618, 'single', '90006', '職業安全衛生法所稱有母性健康危害之虞之工作，係指對於具生育能力之 女性勞工從事工作，可能會導致的一些影響。下列何者除外？', '胚胎發育,妊娠期間之母體健康,哺乳期間之幼兒健康,經期紊亂 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000619, 'single', '90006', '下列何者非屬職業安全衛生法規定之勞工法定義務？', '定期接受健康檢查,參加安全衛生教育訓練,實施自動檢查,遵守安全衛生工作守則 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000620, 'single', '90006', '下列何者非屬應對在職勞工施行之健康檢查？', '一般健康檢查,體格檢 查,特殊健康檢查,特定對象及特定項目之檢查 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000621, 'single', '90006', '下列何者非為防範有害物食入之方法？', '有害物與食物隔離,不在工作 場所進食或飲水,常洗手、漱口,穿工作服 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000622, 'single', '90006', '有關承攬管理責任，下列敘述何者正確？', '原事業單位交付廠商承攬，如 不幸發生承攬廠商所僱勞工墜落致死職業災害，原事業單位應與承攬廠商 負連帶補償及賠償責任,原事業單位交付承攬，不需負連帶補償責任,承攬廠商應自負職業災害之賠償責任,勞工投保單位即為職業災害之賠償 單位 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000623, 'single', '90006', '依勞動基準法規定，主管機關或檢查機構於接獲勞工申訴事業單位違反本 法及其他勞工法令規定後，應為必要之調查，並於幾日內將處理情形，以 書面通知勞工？', '14,20,30,60 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000624, 'single', '90006', '我國中央勞工行政主管機關為下列何者？', '內政部,勞工保險局,勞動 部,經濟部 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000625, 'single', '90006', '對於勞動部公告列入應實施型式驗證之機械、設備或器具，下列何種情形 不得免驗證？', '依其他法律規定實施驗證者,供國防軍事用途使用者,輸入僅供科技研發之專用機,輸入僅供收藏使用之限量品 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000626, 'single', '90006', '對於墜落危險之預防設施，下列敘述何者較為妥適？', '在外牆施工架等高 處作業應盡量使用繫腰式安全帶,安全帶應確實配掛在低於足下之堅固點,高度2m 以上之邊緣開口部分處應圍起警示帶,高度2m 以上之開口處 應設護欄或安全網 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000627, 'single', '90006', '下列對於感電電流流過人體的現象之敘述何者有誤？', '痛覺,強烈痙攣,血壓降低、呼吸急促、精神亢奮,顏面、手腳燒傷 ', '2', '');
