INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000629, 'single', '90006', '下列何者非屬危險物儲存場所應採取之火災爆炸預防措施？', '使用工業用 電風扇,裝設可燃性氣體偵測裝置,使用防爆電氣設備,標示「嚴禁煙 火」 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000630, 'single', '90006', '雇主於臨時用電設備加裝漏電斷路器，可減少下列何種災害發生？', '墜落,物體倒塌、崩塌,感電,被撞 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000631, 'single', '90006', '雇主要求確實管制人員不得進入吊舉物下方，可避免下列何種災害發生？', '感電,墜落,物體飛落,缺氧 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000632, 'single', '90006', '職業上危害因子所引起的勞工疾病，稱為何種疾病？', '職業疾病,法定 傳染病,流行性疾病,遺傳性疾病 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000633, 'single', '90006', '事業招人承攬時，其承攬人就承攬部分負雇主之責任，原事業單位就職業 災害補償部分之責任為何？', '視職業災害原因判定是否補償,依工程性 質決定責任,依承攬契約決定責任,仍應與承攬人負連帶責任 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000634, 'single', '90006', '預防職業病最根本的措施為何？', '實施特殊健康檢查,實施作業環境改 善,實施定期健康檢查,實施僱用前體格檢查 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000635, 'single', '90006', '以下為假設性情境:「在地下室作業，當通風換氣充分時，則不易發生一氧 化碳中毒或缺氧危害」，請問「通風換氣充分」係指「一氧化碳中毒或缺 氧危害」之何種描述？', '風險控制方法,發生機率,危害源,風險 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000636, 'single', '90006', '勞工為節省時間，在未斷電情況下清理機臺，易發生危害為何？', '捲夾感 電,缺氧,墜落,崩塌 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000637, 'single', '90006', '工作場所化學性有害物進入人體最常見路徑為下列何者？', '口腔,呼吸 道,皮膚,眼睛 ', '1', '');
