INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000639, 'single', '90006', '下列何者非屬電氣災害類型？', '電弧灼傷,電氣火災,靜電危害,雷電 閃爍 ', '3', '');
