INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000641, 'single', '90006', '在噪音防治之對策中，從下列哪一方面著手最為有效？', '偵測儀器,噪 音源,傳播途徑,個人防護具 ', '1', '');
