INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000644, 'single', '90006', '下列何者非為職業病預防之危害因子？', '遺傳性疾病,物理性危害,人 因工程危害,化學性危害 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000645, 'single', '90006', '下列何者非屬使用合梯，應符合之規定？', '合梯應具有堅固之構造,合 梯材質不得有顯著之損傷、腐蝕等,梯腳與地面之角度應在80 度以上,有安全之防滑梯面 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000646, 'single', '90006', '下列何者非屬勞工從事電氣工作，應符合之規定？', '使其使用電工安全帽,穿戴絕緣防護具,停電作業應檢電掛接地,穿戴棉質手套絕緣 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000647, 'single', '90006', '為防止勞工感電，下列何者為非？', '使用防水插頭,避免不當延長接線,設備有金屬外殼保護即可免裝漏電斷路器,電線架高或加以防護 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000648, 'single', '90006', '不當抬舉導致肌肉骨骼傷害或肌肉疲勞之現象，可稱之為下列何者？', '感 電事件,不當動作,不安全環境,被撞事件 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000649, 'single', '90006', '使用鑽孔機時，不應使用下列何護具？', '耳塞,防塵口罩,棉紗手套,護目鏡 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000650, 'single', '90006', '腕道症候群常發生於下列何種作業？', '電腦鍵盤作業,潛水作業,堆高 機作業,第一種壓力容器作業 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000651, 'single', '90006', '對於化學燒傷傷患的一般處理原則，下列何者正確？', '立即用大量清水沖 洗,傷患必須臥下，而且頭、胸部須高於身體其他部位,於燒傷處塗抹 油膏、油脂或發酵粉,使用酸鹼中和 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000652, 'single', '90006', '下列何者非屬防止搬運事故之一般原則？', '以機械代替人力,以機動車 輛搬運,採取適當之搬運方法,儘量增加搬運距離 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000653, 'single', '90006', '對於脊柱或頸部受傷患者，下列何者不是適當的處理原則？', '不輕易移動 傷患,速請醫師,如無合用的器材，需2 人作徒手搬運,向急救中心聯 絡 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000654, 'single', '90006', '防止噪音危害之治本對策為下列何者？', '使用耳塞、耳罩,實施職業安 全衛生教育訓練,消除發生源,實施特殊健康檢查 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000655, 'single', '90006', '安全帽承受巨大外力衝擊後，雖外觀良好，應採下列何種處理方式？', '廢 棄,繼續使用,送修,油漆保護 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000656, 'single', '90006', '因舉重而扭腰係由於身體動作不自然姿勢，動作之反彈，引起扭筋、扭腰 及形成類似狀態造成職業災害，其災害類型為下列何者？', '不當狀態,不當動作,不當方針,不當設備 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000657, 'single', '90006', '下列有關工作場所安全衛生之敘述何者有誤？', '對於勞工從事其身體或衣 著有被污染之虞之特殊作業時，應備置該勞工洗眼、洗澡、漱口、更衣、 洗濯等設備,事業單位應備置足夠急救藥品及器材,事業單位應備置足 夠的零食自動販賣機,勞工應定期接受健康檢查 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000658, 'single', '90006', '毒性物質進入人體的途徑，經由那個途徑影響人體健康最快且中毒效應最 高？', '吸入,食入,皮膚接觸,手指觸摸 ', '1', '');
