INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000672, 'single', '90006', '若勞工工作性質需與陌生人接觸、工作中需處理不可預期的突發事件或工 作場所治安狀況較差，較容易遭遇下列何種危害？', '組織內部不法侵害,組織外部不法侵害,多發性神經病變,潛涵症 ', '1', '');
