INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000676, 'single', '90006', '以下關於「童工」之敘述，何者正確？', '每日工作時間不得超過8 小時,不得於午後8 時至翌晨8 時之時間內工作,例假日得在監視下工作,工資不得低於基本工資之70％ ', '0', '');
