INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000678, 'single', '90006', '工作者若因雇主違反職業安全衛生法規定而發生職業災害、疑似罹患職業 病或身體、精神遭受不法侵害所提起之訴訟，得向勞動部委託之民間團體 提出下列何者？', '災害理賠,申請扶助,精神補償,國家賠償 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000679, 'single', '90006', '計算平日加班費須按平日每小時工資額加給計算，下列敘述何者有誤？', '前2 小時至少加給1/3 倍,超過2 小時部分至少加給2/3 倍,經勞資協商 同意後，一律加給0.5 倍,未經雇主同意給加班費者，一律補休 ', '3', '');
