INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000681, 'single', '90006', '下列工作場所何者非屬法定危險性工作場所？', '農藥製造,金屬表面處 理,火藥類製造,從事石油裂解之石化工業之工作場所 ', '1', '');
